Examples:
create procedure
fib (in n integer)
{
  if (n <= 2) return 1;
  return fib (n - 1) + fib (n - 2);
}
;
create procedure
time_fib (in n integer)
{
  declare t,i integer;
  declare msg varchar;
  result_names (msg);
  t := msec_time();
  i := fib (n);
  result (sprintf ('fib (%d) is %d, got it in %d milliseconds.',
	           n, i, msec_time() - t));
}
;
SQL> time_fib(10);
msg
VARCHAR NOT NULL
fib (10) is 55, got it in 10 milliseconds.
1 Rows. -- 21 msec.
